"use client";

import { useState, useRef, useEffect, forwardRef, useCallback, useMemo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronLeft, ChevronRight, AlertCircle, X, Sparkles, BookOpen } from "lucide-react";
import type { GenerationProgress } from "@/lib/api";

/**
 * Turkish possessive suffix after apostrophe (iyelik eki).
 * Rules follow vowel harmony (b├╝y├╝k ├╝nl├╝ uyumu):
 *   Back vowels (a,─▒,o,u) ÔåÆ ─▒n/n─▒n/nun/un; Front vowels (e,i,├Â,├╝) ÔåÆ in/nin/n├╝n/├╝n
 *   Ends in vowel ÔåÆ 'n─▒n / 'nin / 'nun / 'n├╝n
 *   Ends in consonant ÔåÆ '─▒n / 'in / 'un / '├╝n
 */
function getTurkishPossessiveSuffix(name: string): string {
  if (!name) return "─▒n";
  const last = name.slice(-1).toLowerCase();
  const secondLast = name.length > 1 ? name.slice(-2, -1).toLowerCase() : "";
  const isVowel = (c: string) => "ae─▒io├Âu├╝".includes(c);

  const lastVowel =
    Array.from(name.toLowerCase())
      .filter((c) => isVowel(c))
      .at(-1) ?? "a";
  const endsInVowel = isVowel(last);

  const suffixMap: Record<string, [string, string]> = {
    a: ["n─▒n", "─▒n"],
    ─▒: ["n─▒n", "─▒n"],
    e: ["nin", "in"],
    i: ["nin", "in"],
    o: ["nun", "un"],
    u: ["nun", "un"],
    ├Â: ["n├╝n", "├╝n"],
    ├╝: ["n├╝n", "├╝n"],
  };

  const [vowelSuffix, consonantSuffix] = suffixMap[lastVowel] ?? ["n─▒n", "─▒n"];
  // Suppress unused warning
  void secondLast;
  return endsInVowel ? vowelSuffix : consonantSuffix;
}

interface ImagePreviewStepProps {
  childName: string;
  previewImages: { [key: number | string]: string };
  onApprove: () => void;
  onBack: () => void;
  onReportIssue?: (issue: string) => void;
  isLoading?: boolean;
  backCoverImageUrl?: string | null;
}

// Cover Page component with glossy effect
const CoverPage = forwardRef<HTMLDivElement, { imageUrl: string; isFront?: boolean }>(
  ({ imageUrl, isFront = true }, ref) => {
    return (
      <div ref={ref} className="page-content cover-page">
        <div className="relative h-full w-full overflow-hidden">
          {imageUrl ? (
            <>
              <img
                src={imageUrl}
                alt="Kapak"
                className="h-full w-full object-contain"
                draggable={false}
              />
              {/* Subtle glossy overlay effect ÔÇö kept light to preserve image quality */}
              <div
                className="pointer-events-none absolute inset-0"
                style={{
                  background: `
                    linear-gradient(
                      135deg, 
                      rgba(255,255,255,0.1) 0%, 
                      rgba(255,255,255,0.04) 30%,
                      transparent 50%,
                      rgba(0,0,0,0.04) 80%,
                      rgba(0,0,0,0.08) 100%
                    )
                  `,
                }}
              />
              {/* Subtle light reflection stripe */}
              <div
                className="pointer-events-none absolute inset-0"
                style={{
                  background: `
                    linear-gradient(
                      105deg,
                      transparent 40%,
                      rgba(255,255,255,0.06) 45%,
                      rgba(255,255,255,0.12) 50%,
                      rgba(255,255,255,0.06) 55%,
                      transparent 60%
                    )
                  `,
                }}
              />
              {/* Edge highlight for 3D effect */}
              {isFront && (
                <div className="pointer-events-none absolute bottom-0 right-0 top-0 w-3 bg-gradient-to-l from-black/10 to-transparent" />
              )}
            </>
          ) : (
            <div className="flex h-full w-full items-center justify-center bg-gradient-to-br from-amber-800 to-amber-950">
              <div className="text-center text-amber-200/60">
                <BookOpen className="mx-auto mb-3 h-16 w-16 opacity-50" />
                <p>Kapak y├╝kleniyor...</p>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }
);
CoverPage.displayName = "CoverPage";

