// Issue Report Modal
function IssueModal({
  isOpen,
  onClose,
  onSubmit,
}: {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (issue: string) => void;
}) {
  const issues = [
    { id: "face", label: "├çocu─şun y├╝z├╝ benzememi┼ş", icon: "­şİò" },
    { id: "quality", label: "G├Ârsel kalitesi d├╝┼ş├╝k", icon: "­şôÀ" },
    { id: "style", label: "Stil bekledi─şim gibi de─şil", icon: "­şÄ¿" },
    { id: "content", label: "─░├ğerik hikayeyle uyu┼şmuyor", icon: "­şôû" },
    { id: "other", label: "Di─şer", icon: "­şÆ¼" },
  ];

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[100] flex items-center justify-center p-4"
