            <div className="mb-6 text-center">
              <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-amber-100">
                <AlertCircle className="h-7 w-7 text-amber-600" />
              </div>
              <h3 className="text-xl font-semibold text-gray-900">Bir Sorun mu Var?</h3>
              <p className="mt-1 text-sm text-gray-500">Sorunu se├ğin, size yard─▒mc─▒ olal─▒m</p>
            </div>

            <div className="space-y-3">
              {issues.map((issue) => (
                <button
                  key={issue.id}
                  onClick={() => {
                    onSubmit(issue.id);
                    onClose();
                  }}
                  className="group flex w-full items-center gap-4 rounded-xl border-2 border-gray-100 p-4 text-left transition-all hover:border-purple-300 hover:bg-purple-50/50"
                >
                  <span className="text-2xl">{issue.icon}</span>
                  <span className="font-medium text-gray-700 group-hover:text-purple-700">
                    {issue.label}
                  </span>
                </button>
              ))}
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

// Loading animation component with progress tracking
function MagicalLoadingAnimation({ progress }: { progress?: GenerationProgress | null }) {
  // Calculate progress percentage
  const getProgressPercent = (): number => {
    if (!progress) return 5; // Indeterminate ÔÇö small amount to show "started"
    const { current_page, total_pages, stage } = progress;
    if (stage === "queued") return 2;
    if (stage === "uploading") return 90;
    if (stage === "composing") return 75;
    // generating_images: scale 5%ÔÇô70% based on pages
    if (total_pages <= 0) return 10;
    return Math.min(5 + (current_page / total_pages) * 65, 70);
  };

  const getStageMessage = (): string => {
    if (!progress) return "Sihirli sayfalar haz─▒rlan─▒yor...";
    const { current_page, total_pages, stage } = progress;
    switch (stage) {
      case "queued":
        return "S─▒ran─▒z bekleniyor...";
      case "generating_images":
        return current_page > 0
          ? `Sayfa ${current_page}/${total_pages} olu┼şturuldu`
          : `G├Ârseller olu┼şturuluyor (0/${total_pages})...`;
      case "composing":
        return "Sayfalar tasarlan─▒yor...";
      case "uploading":
        return "Son dokunu┼şlar yap─▒l─▒yor...";
      default:
        return "Sihirli sayfalar haz─▒rlan─▒yor...";
    }
  };

  const percent = getProgressPercent();
  const message = getStageMessage();

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-center justify-center"
      style={{
        background: "linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)",
      }}
    >
      <div className="relative flex flex-col items-center">
        {/* Animated book */}
        <motion.div
          animate={{
            rotateY: [0, 10, 0, -10, 0],
            scale: [1, 1.02, 1, 1.02, 1],
          }}
          transition={{
            duration: 3,
            repeat: Infinity,
            ease: "easeInOut",
          }}
          className="relative"
        >
          <div className="relative h-48 w-72">
            <motion.div
              animate={{ rotateY: [-5, 5, -5] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="absolute left-0 top-0 h-48 w-36 origin-right rounded-l-lg bg-gradient-to-r from-amber-100 to-amber-50"
              style={{
                boxShadow: "inset -10px 0 20px rgba(0,0,0,0.1)",
              }}
            />
            <motion.div
              animate={{ rotateY: [5, -5, 5] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="absolute right-0 top-0 h-48 w-36 origin-left rounded-r-lg bg-gradient-to-l from-amber-100 to-amber-50"
              style={{
                boxShadow: "inset 10px 0 20px rgba(0,0,0,0.1)",
              }}
            />
            <div className="absolute left-1/2 top-0 h-48 w-2 -translate-x-1/2 rounded-sm bg-amber-800" />
          </div>

          <motion.div
            animate={{
              opacity: [0.3, 0.7, 0.3],
              scale: [1, 1.2, 1],
            }}
            transition={{
              duration: 2,
              repeat: Infinity,
              ease: "easeInOut",
            }}
            className="absolute inset-0 -m-8"
            style={{
              background: "radial-gradient(circle, rgba(255,215,0,0.4) 0%, transparent 70%)",
              filter: "blur(20px)",
            }}
          />
        </motion.div>

        {/* Sparkle particles ÔÇö reduced to 3 for performance */}
        {[...Array(3)].map((_, i) => (
          <motion.div
            key={i}
            animate={{
              y: [-20, -60, -20],
              x: [0, i % 2 === 0 ? 20 : -20, 0],
              opacity: [0, 1, 0],
              scale: [0.5, 1, 0.5],
            }}
            transition={{
              duration: 2 + i * 0.3,
              repeat: Infinity,
              delay: i * 0.2,
            }}
            className="absolute"
            style={{
              left: `${20 + i * 10}%`,
              top: "10%",
            }}
          >
            <Sparkles className="h-4 w-4 text-yellow-300" />
          </motion.div>
        ))}

        {/* Progress bar */}
        <div className="mt-10 w-72">
          <div className="h-2 w-full overflow-hidden rounded-full bg-white/10">
            <motion.div
              className="h-full rounded-full"
              style={{
                background: "linear-gradient(90deg, #f59e0b, #fbbf24, #f59e0b)",
                backgroundSize: "200% 100%",
              }}
              initial={{ width: "0%" }}
              animate={{
                width: `${percent}%`,
                backgroundPosition: ["0% 0%", "100% 0%", "0% 0%"],
              }}
              transition={{
                width: { duration: 0.8, ease: "easeOut" },
                backgroundPosition: { duration: 2, repeat: Infinity, ease: "linear" },
              }}
            />
          </div>

          {/* Percentage text */}
          <motion.p
            key={percent}
            initial={{ opacity: 0, y: 4 }}
            animate={{ opacity: 1, y: 0 }}
            className="mt-2 text-right text-xs text-amber-300/60"
          >
            %{Math.round(percent)}
          </motion.p>
        </div>

        {/* Stage message */}
        <AnimatePresence mode="wait">
          <motion.p
            key={message}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.4 }}
            className="mt-4 text-center font-medium text-amber-200"
          >
            {message}
          </motion.p>
        </AnimatePresence>

        {/* Subtle hint */}
        <motion.p
          animate={{ opacity: [0.3, 0.6, 0.3] }}
          transition={{ duration: 3, repeat: Infinity }}
          className="mt-3 text-center text-xs text-amber-200/40"
        >
          Bu i┼şlem 1-3 dakika s├╝rebilir
        </motion.p>
      </div>
    </motion.div>
  );
}

export default function ImagePreviewStep({
  childName,
  previewImages,
  onApprove,
  onBack,
  onReportIssue,
  isLoading = false,
  backCoverImageUrl,
}: ImagePreviewStepProps) {
  const [currentSlide, setCurrentSlide] = useState(0);
  const [showIssueModal, setShowIssueModal] = useState(false);
  const [imagesLoaded, setImagesLoaded] = useState(false);
  const touchStartX = useRef(0);
  const touchStartY = useRef(0);

  // Defensive: treat null/undefined previewImages as empty object
  const _images: Record<string | number, string> = previewImages ?? {};

  // Image mapping:
  //   cover        ÔåÆ key 0
  //   dedication   ÔåÆ key "dedication"  (kar┼ş─▒lama 1)
  //   intro        ÔåÆ key "intro"       (kar┼ş─▒lama 2, always present now)
  //   story pages  ÔåÆ numeric keys > 0, sorted ascending
  const coverImage = _images[0] || "";
  const dedicationImage = _images["dedication"] || "";
  const introImage = (_images as Record<string, string>)["intro"] || "";
  const hasIntro = Boolean(_images["intro"]);

  // Memoized story page keys to avoid recalculation on every render
  const storyPageKeys = useMemo(
    () =>
      Object.keys(_images)
        .filter((k) => k !== "0" && k !== "dedication" && k !== "intro" && !k.includes("back"))
        .map(Number)
        .filter((n) => !Number.isNaN(n) && n > 0)
        .sort((a, b) => a - b),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [previewImages]
  );

  // Slide layout:
  //   0: cover
  //   1: dedication
  //   2 (if hasIntro): intro
  //   2 or 3 ... N: story pages (all of them)
  //   last: back cover (if available)
  // cover=0, dedication=1, [intro=2 if hasIntro], story pages start at (hasIntro?3:2)
  const pagesStartIdx = hasIntro ? 3 : 2;
  const TOTAL_SLIDES = 2 + (hasIntro ? 1 : 0) + storyPageKeys.length + (backCoverImageUrl ? 1 : 0);
  // back cover is always at the last slide index if available
  const backCoverSlideIdx = backCoverImageUrl ? TOTAL_SLIDES - 1 : -1;

  useEffect(() => {
    // Cover image (key 0/"0") must exist for a valid preview.
    // Without it, user sees "Kapak y├╝kleniyor" with no actual content.
    const hasCoverImage = Boolean(_images[0] || _images["0"]);
    if (!isLoading && hasCoverImage) {
      setImagesLoaded(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoading, previewImages]);

  const goNext = useCallback(() => {
    setCurrentSlide((s) => (s < TOTAL_SLIDES - 1 ? s + 1 : s));
  }, [TOTAL_SLIDES]);

  const goPrev = useCallback(() => {
    setCurrentSlide((s) => (s > 0 ? s - 1 : s));
  }, []);

  const goToSlide = useCallback(
    (index: number) => {
      setCurrentSlide(Math.max(0, Math.min(index, TOTAL_SLIDES - 1)));
    },
    [TOTAL_SLIDES]
  );

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    touchStartY.current = e.touches[0].clientY;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const diffX = touchStartX.current - e.changedTouches[0].clientX;
    const diffY = touchStartY.current - e.changedTouches[0].clientY;
    // Only trigger horizontal swipe if horizontal movement dominates
    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY) * 1.5) {
      if (diffX > 0) goNext();
      else goPrev();
    }
  };

  const handleIssueSubmit = (issue: string) => {
    onReportIssue?.(issue);
  };

  // Helper: get slide index for a story page (0-based in storyPageKeys)
  const getStorySlideIdx = (pageIdx: number) => pagesStartIdx + pageIdx;

  if (isLoading || !imagesLoaded) {
    // Loading state now handled by GenerationWaitingModal in PreviewStep
    return null;
  }

  return (
    <>
      <div className="relative overflow-hidden rounded-3xl pb-4" style={{ boxShadow: "0 4px 32px rgba(0,0,0,0.08)" }}>
        {/* Premium Light Background */}
        <div
          className="absolute inset-0 z-0"
          style={{
            background: `linear-gradient(180deg, #f5f3f0 0%, #ebe7e1 100%)`,
          }}
        />

        {/* Content Container */}
        <div className="relative z-10">
          {/* Header */}
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="px-4 pb-3 pt-5 text-center"
          >
            <h1 className="text-lg font-bold tracking-tight text-stone-800 sm:text-xl md:text-2xl">
              {childName}&apos;{getTurkishPossessiveSuffix(childName)} Kitab─▒ Haz─▒r! Ô£¿
            </h1>
            <p className="mt-1 text-xs text-stone-400">Kayd─▒rarak veya oklarla sayfalar─▒ inceleyin</p>
          </motion.div>

          {/* Sayfa viewer */}
          <motion.div
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.25, duration: 0.4 }}
            className="relative px-12 py-2 sm:px-14 md:px-16"
            onTouchStart={handleTouchStart}
            onTouchEnd={handleTouchEnd}
          >
            {/* Sol ok */}
            <button
              type="button"
              onClick={goPrev}
              disabled={currentSlide <= 0}
              className="absolute left-0 top-1/2 z-20 flex h-10 w-10 -translate-y-1/2 items-center justify-center rounded-full bg-white/90 text-stone-600 backdrop-blur-sm transition-all hover:scale-110 hover:bg-white disabled:opacity-20 sm:left-1 sm:h-12 sm:w-12"
              style={{ boxShadow: "0 2px 12px rgba(0,0,0,0.12)" }}
              aria-label="├ûnceki sayfa"
            >
              <ChevronLeft className="h-5 w-5 sm:h-6 sm:w-6" />
            </button>

            {/* Tek sayfa alan─▒ ÔÇö tam geni┼şlikte tek resim */}
            <div
              className="relative mx-auto w-full max-w-2xl overflow-hidden rounded-2xl bg-white ring-1 ring-stone-200/50"
              style={{
                aspectRatio: "4 / 3",
                boxShadow: "0 8px 40px rgba(0,0,0,0.12)",
              }}
            >
              <AnimatePresence mode="wait">
                {/* Kapak */}
                {currentSlide === 0 && (
                  <motion.div
                    key="cover"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.25 }}
                    className="absolute inset-0"
                  >
                    <CoverPage imageUrl={coverImage} isFront={true} ref={null} />
                  </motion.div>
                )}
                {/* Kar┼ş─▒lama 1 - ─░thaf sayfas─▒ */}
                {currentSlide === 1 && (
                  <motion.div
                    key="dedication"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.25 }}
                    className="absolute inset-0"
                  >
                    <DedicationPage childName={childName} imageUrl={dedicationImage} ref={null} />
                  </motion.div>
                )}
                {/* Kar┼ş─▒lama 2 - iste─şe ba─şl─▒ intro sayfas─▒ */}
                {hasIntro && currentSlide === 2 && (
                  <motion.div
                    key="intro"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.25 }}
                    className="absolute inset-0"
                  >
                    <DedicationPage childName={childName} imageUrl={introImage} ref={null} />
                  </motion.div>
                )}
                {/* T├£M hikaye sayfalar─▒ ÔÇö d├Âng├╝yle */}
                {storyPageKeys.map((pageKey, pageIdx) => {
                  const slideIdx = getStorySlideIdx(pageIdx);
                  return currentSlide === slideIdx ? (
                    <motion.div
                      key={`story-page-${pageKey}`}
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      transition={{ duration: 0.25 }}
                      className="absolute inset-0"
                    >
                      <InnerPage
                        imageUrl={_images[pageKey] || ""}
                        pageNumber={pageIdx + 1}
                        side={pageIdx % 2 === 0 ? "left" : "right"}
                        ref={null}
                      />
                    </motion.div>
                  ) : null;
                })}
                {/* Arka kapak */}
                {backCoverImageUrl && currentSlide === backCoverSlideIdx && (
                  <motion.div
                    key="back"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.25 }}
                    className="absolute inset-0"
                  >
                    <CoverPage imageUrl={backCoverImageUrl} isFront={false} ref={null} />
                  </motion.div>
                )}
                {/* Arka kapak (resim yoksa dekoratif) */}
                {!backCoverImageUrl &&
                  currentSlide === TOTAL_SLIDES - 1 &&
                  storyPageKeys.length > 0 && (
                    <motion.div
                      key="back-default"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, x: -20 }}
                      transition={{ duration: 0.25 }}
                      className="absolute inset-0"
                    >
                      <BackCover ref={null} />
                    </motion.div>
                  )}
              </AnimatePresence>
            </div>

            {/* Sa─ş ok */}
            <button
              type="button"
              onClick={goNext}
              disabled={currentSlide >= TOTAL_SLIDES - 1}
              className="absolute right-0 top-1/2 z-20 flex h-10 w-10 -translate-y-1/2 items-center justify-center rounded-full bg-white/90 text-stone-600 backdrop-blur-sm transition-all hover:scale-110 hover:bg-white disabled:opacity-20 sm:right-1 sm:h-12 sm:w-12"
              style={{ boxShadow: "0 2px 12px rgba(0,0,0,0.12)" }}
              aria-label="Sonraki sayfa"
            >
              <ChevronRight className="h-5 w-5 sm:h-6 sm:w-6" />
            </button>
          </motion.div>

          {/* Sayfa g├Âstergesi */}
          <div className="mt-3 flex flex-col items-center gap-2 px-2">
            <p className="text-xs font-semibold uppercase tracking-wide text-stone-500">
              {[
                "Kapak",
                "─░thaf",
                ...(hasIntro ? ["Giri┼ş"] : []),
                ...storyPageKeys.map((_, i) => `Sayfa ${i + 1}`),
                ...(backCoverImageUrl ? ["Arka Kapak"] : []),
              ][currentSlide] ?? ""}
              <span className="ml-2 font-normal text-stone-400">
                {currentSlide + 1} / {TOTAL_SLIDES}
              </span>
            </p>
            <div className="flex flex-wrap items-center justify-center gap-1.5 px-4">
              {Array.from({ length: TOTAL_SLIDES }).map((_, idx) => (
                <button
                  key={`dot-${idx}`}
                  type="button"
                  onClick={() => goToSlide(idx)}
                  aria-label={`Sayfa ${idx + 1}`}
                  className={`touch-manipulation rounded-full transition-all duration-200 ${currentSlide === idx
                    ? "h-2 w-6 bg-indigo-600"
                    : "h-2 w-2 bg-stone-300 hover:bg-stone-400"
                    }`}
                />
              ))}
            </div>
          </div>
        </div>

        {/* Issue report link */}
        <div className="mt-3 flex justify-center">
          <button
            onClick={() => setShowIssueModal(true)}
            className="flex items-center gap-2 text-xs text-stone-400 transition-colors hover:text-stone-600"
          >
            <AlertCircle className="h-3.5 w-3.5" />
            Bir sorun mu var?
          </button>
        </div>
      </div>

      {/* Issue Report Modal */}
      <IssueModal
        isOpen={showIssueModal}
        onClose={() => setShowIssueModal(false)}
        onSubmit={handleIssueSubmit}
      />

      {/* Approve / Back CTA buttons */}
      <div
        className="sticky bottom-0 z-[60] bg-white/95 px-4 py-3 backdrop-blur-xl"
        style={{
          paddingBottom: "max(0.75rem, env(safe-area-inset-bottom, 0px))",
          boxShadow: "0 -1px 3px rgba(0,0,0,0.03), 0 -4px 16px rgba(0,0,0,0.04)",
        }}
      >
        <div className="mx-auto flex max-w-lg gap-3">
          {onBack && (
            <button
              type="button"
              onClick={onBack}
              className="flex h-12 items-center px-4 text-sm font-medium text-stone-500 transition-colors hover:text-stone-700 sm:h-14"
            >
              ÔåÉ Geri
            </button>
          )}
          {onApprove && (
            <button
              type="button"
              onClick={onApprove}
              className="flex h-12 flex-1 items-center justify-center gap-2 rounded-2xl bg-indigo-600 text-sm font-semibold tracking-wide text-white transition-all duration-200 hover:bg-indigo-700 active:bg-indigo-800 sm:h-14 sm:text-base"
              style={{ boxShadow: "0 4px 16px rgba(99,102,241,0.15)" }}
            >
              <Sparkles className="h-4 w-4" aria-hidden="true" />
              Hikayemi Onayla & Devam Et
            </button>
          )}
        </div>
      </div>
    </>
  );
}
